INSERT INTO places VALUES(1,1,'APFELBAUER','Idylle inmitten der Wiener Hausberge. Großartige Küche mit Produkten aus der Region, Spielplatz am Bach, gute Kinder-Menüs.','Ascherstr. 15','2761','Miesenbach','Österreich','02632/8244','Mi-Sa 11-21, So 11-20','www.apfelbauer.at',NULL);
INSERT INTO places VALUES(2,1,'BONKA','Ein Gasthaus, wie es im Buche steht, nur besser bekocht. Und auferdem Spielplatz, Pferde und jede Menge grüner Wienerwald.','Oberkirchbach 61','3413','Oberkirchbach','Österreich','02242/62 90','Mi-Sa 9-21, So, Fei 9-16','www.bonka.at',NULL);
INSERT INTO places VALUES(3,1,'NIERSCHER','Das Essen ist hier auf Edelheurigen-Niveau, die Atmosphäre urig, das Angebot für Kinder umso prachtvoller: Platz, Streichelzoo, Obstgarten.','Hauptstr. 190','3400','Weidling','Österreich','02243/339 33','Di-Fr 15-24, Sa, So, Fei 12-24','www.nierscher.at',NULL);
INSERT INTO places VALUES(4,1,'STOCKERWIRT','Der Familien-Klassiker. Spielplatz, kleines Biotop mit Bach, Spielzeug. Zu beachten: Kinder wollen nicht warten, der Andrang ist oft groß.','Hauptstr. 36','2392','Sulz im Wienerwald','Österreich','02238/82 590','Mi-Sa 11.30-22, So, Fei 11-21','www.stockerwirt.com',NULL);
INSERT INTO places VALUES(5,1,'BLAA-ALM','Hier können sich nicht nur die Zwerge am Spielplatz mitten auf der Alm austoben, auch Eltern bekommen alles, was eine Hütte bieten kann.','Lichtersberg 73','8992','Altaussee','Österreich','03622/71 102','Mo-So 9-24','www.blaa-alm.at',NULL);
INSERT INTO places VALUES(6,1,'Mirli','Ein 1792 erbautes Forsthaus mit atemberaubendem Blick über die grünen Hügel eines außerordentlich schönen Stückerls Wienerwald, keine 15 Minuten von der Wiener Stadtgrenze entfernt.','Heinratsberg 69','3011','Tullnerbach/Irenental','Österreich','0664/22231 31','Mi-So, Fei 11.30-24','www.mirli.at',NULL);
INSERT INTO places VALUES(7,1,'Araz','Das jüngste Top-Hotel Budapests, das Continental, befindet sich im früheren Jugendstil-Bad Hungäria, sein Restaurant Araz hat schon viele Preise eingeheimst. Gekocht wird eine französisch-ungarische Fusionsküche.','Dohány utca 42-44','2+36','Budapest','Ungarn','2+36/1/815 1100','Mo-So 7-23','www.araz.hu',NULL);
INSERT INTO places VALUES(8,6,'Quellenhof Luxury Resort Lazise','Umgeben von Oliven- und Pinienhainen, oberhalb des malerischen Städtchens, genießt man atemberaubende Ausblicke auf das Süd-Ostufer des Garda-sees.',NULL,NULL,'Lazise','Italien',NULL,NULL,'www.quellenhof-lazise.it','+');
INSERT INTO places VALUES(9,6,'Klausen','Der Winter in Klausen erzählt von Stille, die knirscht, wenn Schritte Spuren in den Schnee zeichnen.','Eisacktal, Südtirol',NULL,'Klausen','Italien',NULL,NULL,'www.klausen.it','+');
INSERT INTO places VALUES(14,14,'Cafe Drechsler','Ein junger Kellner hilft, einen Platz zu finden, obwohl es nur um einen schnellen Espresso geht.','Linke Wienzeile 22, Wien 6',NULL,'Wien','Österreich',NULL,NULL,NULL,'+');
INSERT INTO places VALUES(15,14,'Ganko Il','Qualität und Zubereitung unserer Speisen sind top. Die Wartezeit im halb leeren Lokal auf Essen und Trinken ist unverhältnismäßig lang.','Heinrichsg. 6, Wien I',NULL,'Wien','Österreich',NULL,NULL,NULL,'+/-');
INSERT INTO places VALUES(22,20,'Kühstein.haus','Regionaler Kühsteingraben 14, Langenlois','Kühsteingraben 14, Langenlois',NULL,'Langenlois','Österreich',NULL,NULL,NULL,'+');
INSERT INTO places VALUES(23,20,'MAK-Cafe','Gemütlicher Salon für Gäste, der auch etwas essen muss','nicht genannt',NULL,'Wien','Österreich',NULL,NULL,NULL,'-');
INSERT INTO places VALUES(24,19,'Stuttnerhof','Vom Heurigen zum Restaurant umgestaltetes Lokal. Beim ersten Besuch gab es Missverständnisse bei Bestellungen, die Reaktion war jedoch sehr freundlich mit Gutschein.','Josef-Dabsch-Str. 9',NULL,'Bisamberg','Österreich',NULL,NULL,NULL,'+/-');
INSERT INTO places VALUES(25,19,'Hotel Galäntha Roof-Top-Bar','Roof-Top-Bar mit Timeslots von 1,5 Stunden. Musik konnte trotz Bitte nicht leiser gestellt werden.','Esterhazyplatz 3',NULL,'Eisenstadt','Österreich',NULL,'ab 16 Uhr',NULL,'-');
INSERT INTO places VALUES(26,13,'cookionista','Kochschule in Nürnberg, bietet Lebkuchen-Workshops und diverse Kurse zu Thai-Food, Sushi, Veggie-Küche u.v.m. an.','hinter dem Graben, nordwestliche Ecke',NULL,'Nürnberg','Deutschland',NULL,NULL,'cookionista.com','+');
INSERT INTO places VALUES(27,13,'Gebr. Fraunholz Elisenlebküchnerei','Traditionelle Lebküchnerei, backt Elisenlebkuchen ohne Mehl nach alter Tradition.',NULL,NULL,'Nürnberg','Deutschland',NULL,NULL,'fraunholz-lebkuchen.de','+');
INSERT INTO places VALUES(28,13,'Savester Winterdorf','Winterdorf mit Riesenrad am Jakobsplatz hinter dem Weißen Turm, eröffnet am 24. Dezember.','Am Jakobsplatz',NULL,'Nürnberg','Deutschland',NULL,'24. Dezember bis 7. Jänner 2024','nuernberg.de',NULL);
INSERT INTO places VALUES(29,3,'Gasthof Fürberg','Empfohlener Gasthof am Wolfgangsee für Reinanke oder Saibling, mit Uferpromenade nach St. Gilgen.',NULL,NULL,'Fürberg','Österreich',NULL,NULL,NULL,'+');
INSERT INTO places VALUES(30,3,'Hotel Weisses Rössl','Traditionshotel am Wolfgangsee, Ausgangspunkt für Wanderungen auf Zwölferhorn, Postalm und Schafberg.',NULL,NULL,'St. Wolfgang','Österreich',NULL,NULL,NULL,'+');
INSERT INTO places VALUES(31,3,'Galerie Max Leonhard','Atelier des Südtiroler Künstlers Max Leonhard mit wind- und wetterfesten Silikon-Außenbildern.','Weg von St. Wolfgang nach Strobl',NULL,'Strobl','Österreich',NULL,NULL,NULL,NULL);
INSERT INTO places VALUES(32,10,'Kuffner-Sternwarte','Sternwarte in Wien, Ausgangspunkt für die Sternfahrt zu den Geminidenschnuppen am 13. Dezember 2025 um 17 Uhr.','Johann Staud-Straße 10','1160','Wien','Österreich',NULL,NULL,'geminiden@kuffner-sternwarte.at',NULL);
INSERT INTO books VALUES(1,12,'Fit & schlank mit Brot','Michaela Axt-Gadermann','Südwest Verlag','2025','176','ca. 21 Euro',NULL,'Das Buch von Ernährungsmedizinerin Michaela Axt-Gadermann und Brotsommelier Johannes Dackweiler erklärt, warum viele Brotsorten sehr gesund sind und welche gesundheitsförderlichen Wirkungen Getreide und seine Bestandteile auf Herzgesundheit, Arterkrankungen, Verdauungskreislauf und andere Gesundheitsaspekte haben. Es enthält Backrezepte für unterschiedliche Bedürfnisse, wie glutenfreie oder histaminarme Brote, sowie Ballaststoffe, Proteine und gesunde Fette. Das Buch bietet auch Tipps zur richtigen Auswahl von Brot und dessen Verwendung in der Ernährung.');
INSERT INTO books VALUES(4,13,'Il Milione - Die Wunder der Welt','Marco Polo','Manesse Verlag','2024','432','47,50 Euro','null','Marco Polo hat mit diesem Buch versucht, die Welt aus altfranzösischen und lateinischen Quellen zu übersetzen. Die Übersetzung trifft den Kern des Buches, da sie die Grenzen zwischen Bericht und Fabulierung verschwimmen lässt. Das Buch ist eine wertvolle Versuchung, die Leser für Schmunzeln und Verwunderung sorgt.');
INSERT INTO recipes VALUES(5,12,'Toastys Vollkornbrot','Brot','1 Laib','30 Minuten','Kerne, Kleie, Süßlupinenmehl, Leinsamenschrot und Flohsamenschalen mit Weinsteinbackpulver, Mehlgemisch, Eier, Olivenöl, Balsamicoessig oder Essig, Wasser, Salz','1. Kerne, Kleie, Süßlupinenmehl, Leinsamenschrot und Flohsamenschalen mit Weinsteinbackpulver, Mehlgemisch, Eier, Olivenöl, Balsamicoessig oder Essig, Wasser, Salz verrühren. 2. Die Masse mit Mehlgemisch gut vermengen und kräftig durchkneten. Einen Laib formen, der in einer kleinen Kastenform oder auf einem Backblech gebacken wird. Oberfläche anfeuchten und mit Saaten bestreuen. 3. Das Brot bei 180 °C (Umluft) backen. 4. Tipp: Dazu passt ein cremiger, mild gesäuerter Topfen, angekocht mit Gartenkräutern wie Schnittlauch, Dille sowie einem Schuss Zitronensaft.');
INSERT INTO recipes VALUES(6,12,'Leinsaat-Nuss-Brot','Brot','1 Laib','4 Stunden','Walnüsse, Sonnenblumenkerne, Leinsamen, Flohsamenschalen, Leinsamenmehl, Meerzsalz, Walnussöl, Rohrohrzucker, Wasser','1. Kastenform mit Backpapier auslegen. Walnüsse hacken. Mit den Sonnenblumenkernen, Leinsamen, Flohsamenschalen, Leinsamenmehl und Meerzsalz in einer Rührschüssel mit einem Schneebesen vermischen. 2. Öl, Zucker und 350 ml Wasser in mehreren Portionen mit den Quirlen eines Handrührgeräts unterrühren. Den Teig in Kastenform füllen, glatt streichen und zugedeckt 3 Stunden quellen lassen. 3. Den Backofen auf 180 °C (Ober-/Unterhitze) vorheizen. Das Brot mit Leinsamen bestreuen und im Ofen auf mittlerer Schiene 60-70 Minuten backen. 4. Das Brot aus dem Ofen nehmen und auf Kuchen gitter 10 Minuten abkühlen lassen. Dann aus der Form lösen und vollständig auskühlen lassen. Kühl und trocken gelagert, bleibt es bis zu 1 Woche saftig.');
INSERT INTO recipes VALUES(7,12,'Vollkornweckerl','Brot','8 Stück','ca. 12 Stunden (Übernacht)',replace('250 ml kaltes Wasser\n1 TL Kokosblütenzucker\n15 g frische Hefe\n300 g Dinkelvollkornmehl\n100 g Haferflocken, fein gemahlen\n50 g Leinsamen, geschrotet\n1 TL Salz\n2 EL Olivenöl\nSonnenblumenkerne, Kürbiskerne oder Sesam zum Bestreuen','\n',char(10)),replace('1. Am Vorabend das kalte Wasser mit Kokosblütenzucker mischen und die Hefe darin auflösen.\n2. In einer großen Schüssel Mehl, gemahlene Haferflocken, Leinsamen und Salz vermischen. Hefe-Wasser und Olivenöl hinzugeben und zu einem geschmeidigen, leicht klebrigen Teig kneten.\n3. Den Teig abgedeckt für mindestens 12 Stunden (über Nacht) im Kühlschrank ruhen lassen.\n4. Am nächsten Morgen den Teig aus dem Kühlschrank nehmen und 10-15 Minuten bei Raumtemperatur ruhen lassen. In 8 gleich große Portionen teilen und zu Brötchen formen.\n5. Den Ofen auf 220 °C (Ober-/Unterhitze) vorheizen. Brötchen auf ein Backblech legen und 20-30 Minuten gehen lassen.\n6. Optional: Brötchen mit Wasser bestreichen und mit Kernen/Sesam bestreuen.\n7. 20-25 Minuten backen bis sie goldbraun und knusprig sind. Auf einem Gitter auskühlen lassen.','\n',char(10)));
INSERT INTO recipes VALUES(9,14,'Ingwer, ungefärbt','Eingemachtes','1 Packung','1 Stunde','1 Packung Blätterteig, 1 Becher Schlagobers, 1 Packerl Vanillezucker, Staubzucker, Butter zum Einstreichen','Schalte das Backrohr auf 180 °C. Streiche die Förmchen mit Butter ein. Entrollen den (noch kalten!) Blätterteig und schneide ihn quer in 1 cm breite Streifen. Wickeln die Teigstreifen leicht über Apfölchen und legen sie auf ein füllendes Backblech. Klassisch werden sie mit Backpapier ausgelegtes Backblech. Backe die Rollen mit Heißluft 15-20 Minuten. Nimm sie aus dem Ofen, lasse sie überkühlen und ziehe sie behutsam mit gefüllt, es gibt auch leichter Drehung von den Formen. Füll sie mit Schlagobers samt Vanillezucker Füllungen. Spritze es in die Röllchen. Von Heidi Strobl');
INSERT INTO recipes VALUES(10,15,'POPCORN','Snack','1-2 Kolben','20 Minuten','1-2 Kolben Popcornmais, Maiskeimöl, Salz','1. Löse die Körner mit den Fingern vom Maiskolben ab. Entferne kleine Pflanzenhärchen und -brösel. Alternativ: Kaufe fertig abgerebelte Popcornmaiskörner. 2. Gib 3 EL ÖL in einen geräumigen Topf. Streue die Maiskörner hinein, schwenke sie, sodass alle mit Öl bedeckt sind. 3. Erhitze den Topf, bis das Öl leicht zu blubbern beginnt, dann setze den Deckel auf. 4. Der Mais beginnt nach 2-3 Minuten zu „poppen”. Schüttle den Topf immer wie- der mal durch, ohne den Deckel zu öffnen. 5. Wird es still im Topf, sind alle Körner explodiert. 6. Hebe den Deckel vorsichtig ab. 7. Salze das Popcorn, leere es in eine Schüssel.');
INSERT INTO recipes VALUES(11,16,'VEGANE KNOBLAUCH-MAYO','Snack','5','10 Minuten','Abtropfwasser eines kleinen Glases Kichererbsen (ca 50 ml), YTL englischer Senf, 1 TL Zitronensaft, Ca. 200 ml Raps- oder Sonnenblumenöl, 1-2 Knoblauchzehen, Salz','Lege ein Sieb auf eine schmale Schüssel,schütte die Kichererbsen hinein und lasse sie gut abtropfen. Verwende die Kichererbsen z.B. für Salate oder Hummus. Schäle den Knoblauch, viertle ihn. Gib Senf, Knoblauch und Zitronensaft zum Kichererbsenwasser, mixe es mit einem Handmixgerät oder Stabmixer luftig auf. Jetzt brauchst du Hilfe: einer hält die Schüssel, einer gießt nach und nach Öl dazu und mixt es ein. Zuerst tropfenweise, dann in einem dünnen Strahl. Die Mayonnaise wird immer dicker und fester. Schmecke sie mit Salz und Zitronensaft ab.');
INSERT INTO recipes VALUES(12,17,'POPCORN','Snack','1-2 Kolben','20 Minuten','1-2 Kolben Popcornmais, Maiskeimöl, Salz','1. Löse die Körner mit den Fingern vom Maiskolben ab. Entferne kleine Pflanzenhärchen und -brösel. Alternativ: Kaufe fertig abgerebelte Popcornmaiskörner. 2. Gib 3 EL ÖL in einen geräumigen Topf. Streue die Maiskörner hinein, schwenke sie, sodass alle mit Öl bedeckt sind. 3. Erhitze den Topf, bis das Öl leicht zu blubbern beginnt, dann setze den Deckel auf. 4. Der Mais beginnt nach 2-3 Minuten zu „poppen”. Schüttle den Topf immer wie- der mal durch, ohne den Deckel zu öffnen. 5. Wird es still im Topf, sind alle Körner explodiert. 6. Hebe den Deckel vorsichtig ab. 7. Salze das Popcorn, leere es in eine Schüssel.');
